import (
	"math"
)

func solve(edges [][]int64, online []bool, k int64) int64 {
	n := len(online)
	if n == 0 {
		return -1
	}
	lastNode := int64(n - 1)

	var maxEdge int64 = 0
	for _, e := range edges {
		if e[2] > maxEdge {
			maxEdge = e[2]
		}
	}

	check := func(x int64) bool {
		adj := make([][]struct { to int; cost int64 }, n)
		indeg := make([]int, n)

		for _, e := range edges {
			u, v, c := e[0], e[1], e[2]

			if u != 0 && u != lastNode && !online[u] {
				continue
			}
			if v != 0 && v != lastNode && !online[v] {
				continue
			}
			if v == 0 || u == lastNode {
				continue
			}
			if c < x {
				continue
			}

			uIdx := int(u)
			vIdx := int(v)
			adj[uIdx] = append(adj[uIdx], struct { to int; cost int64 }{vIdx, c})
			indeg[vIdx]++
		}

		dp := make([]int64, n)
		for i := range dp {
			dp[i] = math.MaxInt64
		}
		dp[0] = 0

		q := []int{}
		for i := 0; i < n; i++ {
			if indeg[i] == 0 {
				q = append(q, i)
			}
		}

		for len(q) > 0 {
			node := q[0]
			q = q[1:]
			for _, e := range adj[node] {
				v := e.to
				w := e.cost
				if dp[node] != math.MaxInt64 {
					newCost := dp[node] + w
					if newCost < dp[v] {
						dp[v] = newCost
					}
				}
				indeg[v]--
				if indeg[v] == 0 {
					q = append(q, v)
				}
			}
		}

		return dp[n-1] <= k
	}

	lowX, highX := int64(0), maxEdge
	for lowX <= highX {
		midX := (lowX + highX) / 2
		if check(midX) {
			lowX = midX + 1
		} else {
			highX = midX - 1
		}
	}

	if highX < 0 {
		return -1
	}
	return highX
}
