package main

import (
	"sort"
)

func solve(edges [][]int64, online []bool, k int64) int64 {
	n := len(online)
	if n == 0 {
		return -1
	}

	var baseEdges [][]int64
	costSet := make(map[int64]bool)
	costSet[0] = true
	for _, e := range edges {
		u, v, cost := e[0], e[1], e[2]
		if int(u) < n && int(v) < n && online[u] && online[v] {
			baseEdges = append(baseEdges, []int64{u, v, cost})
			costSet[cost] = true
		}
	}

	distinctCosts := make([]int64, 0, len(costSet))
	for c := range costSet {
		distinctCosts = append(distinctCosts, c)
	}
	sort.Slice(distinctCosts, func(i, j int) bool {
		return distinctCosts[i] < distinctCosts[j]
	})

	adj := make([][]int64, n)
	edgeList := make([][][2]int64, n)
	for _, e := range baseEdges {
		u, v, cost := e[0], e[1], e[2]
		adj[u] = append(adj[u], v)
		edgeList[u] = append(edgeList[u], [2]int64{v, cost})
	}

	visited := make([]bool, n)
	queue := []int64{0}
	visited[0] = true
	for len(queue) > 0 {
		u := queue[0]
		queue = queue[1:]
		for _, v := range adj[u] {
			if !visited[v] {
				visited[v] = true
				queue = append(queue, v)
			}
		}
	}

	if !visited[n-1] {
		return -1
	}

	inDeg := make([]int, n)
	for _, e := range baseEdges {
		u, v := e[0], e[1]
		if visited[u] && visited[v] {
			inDeg[v]++
		}
	}

	q := []int64{}
	for i := 0; i < n; i++ {
		if visited[i] && inDeg[i] == 0 {
			q = append(q, int64(i))
		}
	}
	topoOrder := []int64{}
	for len(q) > 0 {
		u := q[0]
		q = q[1:]
		topoOrder = append(topoOrder, u)
		for _, v := range adj[u] {
			if visited[v] {
				inDeg[v]--
				if inDeg[v] == 0 {
					q = append(q, v)
				}
			}
		}
	}

	lo, hi := 0, len(distinctCosts)-1
	ans := int64(-1)
	inf := int64(1e18)

	check := func(x int64) bool {
		dist := make([]int64, n)
		for i := range dist {
			dist[i] = inf
		}
		dist[0] = 0

		for _, u := range topoOrder {
			if dist[u] == inf {
				continue
			}
			for _, e := range edgeList[u] {
				v, cost := e[0], e[1]
				if cost < x {
					continue
				}
				newCost := dist[u] + cost
				if newCost < dist[v] {
					dist[v] = newCost
				}
			}
		}

		return dist[n-1] <= k
	}

	for lo <= hi {
		mid := (lo + hi) / 2
		x := distinctCosts[mid]
		if check(x) {
			ans = x
			lo = mid + 1
		} else {
			hi = mid - 1
		}
	}

	return ans
}
